#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int a[4];
        for (int i = 0; i < 4; ++i) scanf("%d", &a[i]);
        int possible = 0;
        // generate all permutations using 4 nested loops with distinct indices
        for (int i = 0; i < 4 && !possible; ++i)
            for (int j = 0; j < 4 && !possible; ++j) if (j != i)
                for (int k = 0; k < 4 && !possible; ++k) if (k != i && k != j)
                    for (int l = 0; l < 4 && !possible; ++l) if (l != i && l != j && l != k) {
                        long long x = a[i], y = a[j], z = a[k], w = a[l];
                        if (x * w == y * z) possible = 1;
                    }
        printf("%s\n", possible ? "Possible" : "Impossible");
    }
    return 0;
}

