import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            st = new StringTokenizer(br.readLine());
            int[] a = new int[4];
            for (int i = 0; i < 4; i++) a[i] = Integer.parseInt(st.nextToken());
            boolean possible = false;
            // generate all permutations using recursion
            int[] idx = new int[4];
            boolean[] used = new boolean[4];
            possible = permuteCheck(a, idx, used, 0);
            sb.append(possible ? "Possible" : "Impossible").append('\n');
        }
        System.out.print(sb.toString());
    }

    private static boolean permuteCheck(int[] a, int[] idx, boolean[] used, int pos) {
        if (pos == 4) {
            long x = a[idx[0]], y = a[idx[1]], z = a[idx[2]], w = a[idx[3]];
            return x * w == y * z;
        }
        for (int i = 0; i < 4; i++) {
            if (!used[i]) {
                used[i] = true;
                idx[pos] = i;
                if (permuteCheck(a, idx, used, pos + 1)) return true;
                used[i] = false;
            }
        }
        return false;
    }
}

