#!/usr/bin/env python3
import sys

def possible(nums):
    from itertools import permutations
    for x, y, z, w in permutations(nums):
        if x * w == y * z:
            return True
    return False

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        nums = [int(next(it)) for _ in range(4)]
        out_lines.append("Possible" if possible(nums) else "Impossible")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

