const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
if (input.length === 0) process.exit(0);
const T = input[idx++];
let results = [];
function isPossible(arr) {
  // generate all 24 permutations
  const perm = (a, l) => {
    if (l === a.length) {
      const [x, y, z, w] = a;
      if (x * w === y * z) return true;
      return false;
    }
    for (let i = l; i < a.length; i++) {
      [a[l], a[i]] = [a[i], a[l]];
      if (perm(a, l + 1)) return true;
      [a[l], a[i]] = [a[i], a[l]];
    }
    return false;
  };
  return perm(arr.slice(), 0);
}
for (let t = 0; t < T; t++) {
  const nums = [input[idx++], input[idx++], input[idx++], input[idx++]];
  results.push(isPossible(nums) ? 'Possible' : 'Impossible');
}
console.log(results.join('\n'));

